package bead

import (
	"fmt"
	"strings"
	"time"
)

// Bead represents a portable work item with metadata.
// The schema matches bd/br JSONL format for interchange compatibility.
// Unknown fields from external sources are preserved in Extra.
type Bead struct {
	ID        string    `json:"id"`
	Title     string    `json:"title"`
	Status    string    `json:"status"`
	Priority  int       `json:"priority"`
	IssueType string    `json:"issue_type"`
	Owner     string    `json:"owner,omitempty"`
	CreatedAt time.Time `json:"created_at"`
	CreatedBy string    `json:"created_by,omitempty"`
	UpdatedAt time.Time `json:"updated_at"`

	// Optional fields (bd-compatible)
	Labels      []string `json:"labels,omitempty"`
	Parent      string   `json:"parent,omitempty"`
	Description string   `json:"description,omitempty"`
	Acceptance  string   `json:"acceptance,omitempty"`
	Notes       string   `json:"notes,omitempty"`

	// Dependencies use bd-compatible format
	Dependencies []Dependency `json:"dependencies,omitempty"`

	// Extra holds unknown fields for round-trip preservation.
	// Workflow-specific fields (e.g. HELIX spec-id, execution-eligible)
	// are stored here and written back on save.
	Extra map[string]any `json:"-"`
}

// Dependency represents a link between two beads (bd-compatible format).
type Dependency struct {
	IssueID     string `json:"issue_id"`
	DependsOnID string `json:"depends_on_id"`
	Type        string `json:"type"` // "blocks", "related", etc.
	CreatedAt   string `json:"created_at,omitempty"`
	CreatedBy   string `json:"created_by,omitempty"`
	Metadata    string `json:"metadata,omitempty"`
}

// BeadEvent records append-only execution evidence.
type BeadEvent struct {
	Kind      string    `json:"kind"`
	Summary   string    `json:"summary,omitempty"`
	Body      string    `json:"body,omitempty"`
	Actor     string    `json:"actor,omitempty"`
	CreatedAt time.Time `json:"created_at"`
	Source    string    `json:"source,omitempty"`
}

// Status constants
const (
	StatusOpen       = "open"
	StatusInProgress = "in_progress"
	StatusClosed     = "closed"
	// StatusBlocked marks a bead that is not eligible for agent dispatch —
	// either decomposed into child beads by the triage gate or parked for
	// human intervention after a triage-overflow event. Blocked beads are
	// excluded from ReadyExecution and will not be auto-dispatched.
	StatusBlocked = "blocked"
	// StatusProposed marks an operator-prompt bead awaiting approval. It is
	// excluded from execute-loop drain until transitioned to open via the
	// approval flow, or to cancelled when the operator declines it.
	StatusProposed = "proposed"
	// StatusCancelled marks a bead that was rejected before any execution
	// took place (e.g. an operator-prompt bead the user chose not to run).
	StatusCancelled = "cancelled"
)

// CanonicalStatuses is the single source of truth for the persisted bead
// status enumeration. It mirrors the bd/br canonical set documented in
// TD-031 §2 and the JSON Schema enum at
// cli/internal/bead/schema/bead-record.schema.json. The CI guard tests in
// sync_test.go assert that schema, TD doc, and Go source agree with this
// list; adding or removing a value here without updating the schema and TD
// will fail CI.
var CanonicalStatuses = []string{
	StatusOpen,
	StatusInProgress,
	StatusClosed,
	StatusBlocked,
	StatusProposed,
	StatusCancelled,
}

// IsCanonicalStatus reports whether s is one of the persisted bead statuses
// in CanonicalStatuses.
func IsCanonicalStatus(s string) bool {
	for _, c := range CanonicalStatuses {
		if c == s {
			return true
		}
	}
	return false
}

// IssueType constants
const (
	// IssueTypeOperatorPrompt is the bead type used for operator-submitted
	// prompts that the execute-loop runs as instructions.
	IssueTypeOperatorPrompt = "operator-prompt"
)

// Default labels and other defaults for operator-prompt beads.
const (
	OperatorPromptLabelKind   = "kind:operator-prompt"
	OperatorPromptLabelSource = "source:web-ui"
	// OperatorPromptDefaultAcceptance is the auto-AC stub used when an
	// operator submits a prompt without explicit acceptance criteria. The
	// structural AC verifier is skipped for operator-prompt beads, so this
	// stub stands as a human-readable contract only.
	OperatorPromptDefaultAcceptance = "Agent must produce a diff or no_changes rationale; the prompt body is the contract."
)

// OperatorPromptMutationGuard enforces the no-self-mutation rule from
// Story 15: an operator-prompt bead's execution may not create, edit, or
// close another operator-prompt bead. The guard returns nil when the
// mutation is allowed and a non-nil error when it must be rejected.
//
// actorIssueType is the issue_type of the bead currently being executed
// (empty when no operator-prompt context is active). targetIssueType is
// the issue_type of the bead about to be mutated.
//
// Allow/deny matrix:
//
//	actor=""               , target=*                → allow
//	actor="task"           , target=*                → allow
//	actor="operator-prompt", target!="operator-prompt" → allow
//	actor="operator-prompt", target=="operator-prompt" → deny
func OperatorPromptMutationGuard(actorIssueType, targetIssueType string) error {
	if actorIssueType != IssueTypeOperatorPrompt {
		return nil
	}
	if targetIssueType != IssueTypeOperatorPrompt {
		return nil
	}
	return fmt.Errorf("bead: operator-prompt bead may not mutate another operator-prompt bead")
}

// NewOperatorPromptBead constructs a fresh operator-prompt bead from a raw
// prompt string, applying the Story 15 template defaults: title is the first
// non-empty line of the prompt, full prompt body is preserved verbatim in the
// description, default labels are kind:operator-prompt + source:web-ui, the
// status starts in `proposed` (approval flow), priority defaults to the
// caller-supplied tier (clamped to MinPriority..MaxPriority), and the
// acceptance field carries the auto-AC stub.
//
// The returned bead is not persisted; callers feed it to Store.Create which
// will assign the ID and CreatedAt/UpdatedAt timestamps.
func NewOperatorPromptBead(prompt string, defaultTier int) *Bead {
	body := strings.TrimSpace(prompt)
	title := body
	if i := strings.IndexByte(body, '\n'); i >= 0 {
		title = strings.TrimSpace(body[:i])
	}
	if title == "" {
		title = "(empty operator prompt)"
	}
	tier := defaultTier
	if tier < MinPriority {
		tier = MinPriority
	}
	if tier > MaxPriority {
		tier = MaxPriority
	}
	return &Bead{
		Title:       title,
		IssueType:   IssueTypeOperatorPrompt,
		Status:      StatusProposed,
		Priority:    tier,
		Labels:      []string{OperatorPromptLabelKind, OperatorPromptLabelSource},
		Description: body,
		Acceptance:  OperatorPromptDefaultAcceptance,
	}
}

// Default values
const (
	DefaultType     = "task"
	DefaultStatus   = StatusOpen
	DefaultPriority = 2
	DefaultPrefix   = "bx" // used only when repo name detection fails
	MinPriority     = 0
	MaxPriority     = 4
)

// StatusCounts holds aggregate counts for a bead store.
type StatusCounts struct {
	Open    int `json:"open"`
	Closed  int `json:"closed"`
	Blocked int `json:"blocked"`
	Ready   int `json:"ready"`
	Total   int `json:"total"`
}

// Blocker kinds surfaced through BlockedAll. These strings are part of the
// external DDx contract (HELIX reads them to decide how to handle a blocker).
const (
	BlockerKindDependency         = "dependency"
	BlockerKindBlockedStatus      = "blocked-status"
	BlockerKindRetryCooldown      = "retry-cooldown"
	BlockerKindNeedsInvestigation = "needs-investigation"
	BlockerKindNotEligible        = "not-execution-eligible"
	BlockerKindSuperseded         = "superseded"
	BlockerKindEpicOnly           = "epic-only"
)

// Blocker describes why an open bead is currently not runnable. Either
// unclosed dependencies exist, or an execute-loop cooldown has parked the
// bead until NextEligibleAt.
type Blocker struct {
	Kind           string   `json:"kind"`

package bead

import (
	"bufio"
	"bytes"
	"encoding/json"
	"fmt"
	"os"
	"path/filepath"
	"strings"
	"time"
)

// EventsAttachmentExtraKey is the Extra map key under which a closed/archived
// bead records the path to its externalized events.jsonl sidecar. Per ADR-004
// §"Attachment Model", attachment references live in preserved extras and
// must not shadow bd/br envelope fields. The value is a path relative to
// `<.ddx-dir>/attachments/`, e.g. "ddx-abcdef12/events.jsonl".
const EventsAttachmentExtraKey = "events_attachment"

// EventsAttachmentFileName is the conventional sidecar filename for
// externalized events.
const EventsAttachmentFileName = "events.jsonl"

// attachmentDir returns the absolute directory under .ddx/attachments/ that
// owns this bead's sidecars.
func (s *Store) attachmentDir(beadID string) string {
	return filepath.Join(s.Dir, "attachments", beadID)
}

// eventsAttachmentPath returns the absolute path to a bead's events.jsonl
// sidecar.
func (s *Store) eventsAttachmentPath(beadID string) string {
	return filepath.Join(s.attachmentDir(beadID), EventsAttachmentFileName)
}

// eventsAttachmentRelPath returns the path stored in Extra[events_attachment]:
// it's relative to .ddx/attachments/ and uses forward slashes regardless of
// platform so the value round-trips through bd/br interchange unchanged.
func eventsAttachmentRelPath(beadID string) string {
	return beadID + "/" + EventsAttachmentFileName
}

// hasEventsAttachment reports whether the bead carries an externalized events
// sidecar reference.
func hasEventsAttachment(b *Bead) bool {
	if b == nil || b.Extra == nil {
		return false
	}
	v, ok := b.Extra[EventsAttachmentExtraKey].(string)
	return ok && strings.TrimSpace(v) != ""
}

// readEventsAttachment loads a bead's externalized events from disk. Missing
// file is treated as an empty event log so a half-written close does not
// crash the read path; it returns ([]BeadEvent{}, nil) in that case.
func (s *Store) readEventsAttachment(beadID string) ([]BeadEvent, error) {
	path := s.eventsAttachmentPath(beadID)
	data, err := os.ReadFile(path)
	if os.IsNotExist(err) {
		return []BeadEvent{}, nil
	}
	if err != nil {
		return nil, fmt.Errorf("bead: read events attachment %s: %w", path, err)
	}
	scanner := bufio.NewScanner(bytes.NewReader(data))
	scanner.Buffer(make([]byte, 0, 64*1024), 16*1024*1024)
	var out []BeadEvent
	for scanner.Scan() {
		line := bytes.TrimSpace(scanner.Bytes())
		if len(line) == 0 {
			continue
		}
		var m map[string]any
		if err := json.Unmarshal(line, &m); err != nil {
			return nil, fmt.Errorf("bead: parse events attachment %s: %w", path, err)
		}
		out = append(out, beadEventFromMap(m))
	}
	if err := scanner.Err(); err != nil {
		return nil, fmt.Errorf("bead: scan events attachment %s: %w", path, err)
	}
	if out == nil {
		out = []BeadEvent{}
	}
	return out, nil
}

// writeEventsAttachment writes the given events to the bead's sidecar file
// atomically (temp + rename) and creates the parent directory. An empty
// slice removes the sidecar.
func (s *Store) writeEventsAttachment(beadID string, events []BeadEvent) error {
	dir := s.attachmentDir(beadID)
	path := s.eventsAttachmentPath(beadID)
	if len(events) == 0 {
		_ = os.Remove(path)
		return nil
	}
	if err := os.MkdirAll(dir, 0o755); err != nil {
		return fmt.Errorf("bead: mkdir attachments: %w", err)
	}
	var buf bytes.Buffer
	enc := json.NewEncoder(&buf)
	enc.SetEscapeHTML(false)
	for _, e := range events {
		row := map[string]any{
			"kind":       e.Kind,
			"summary":    e.Summary,
			"body":       e.Body,
			"actor":      e.Actor,
			"created_at": e.CreatedAt.UTC().Format(time.RFC3339Nano),
			"source":     e.Source,
		}
		if err := enc.Encode(row); err != nil {
			return fmt.Errorf("bead: encode events attachment: %w", err)
		}
	}
	return writeAtomicFile(path, buf.Bytes())
}

// eventsForBead returns the bead's events from whichever physical store
// currently holds them: the inline Extra["events"] array, or the externalized
// sidecar referenced by Extra[events_attachment]. When both are present the
// sidecar wins, matching the externalize-then-clear ordering used by Close.
func (s *Store) eventsForBead(b *Bead) ([]BeadEvent, error) {
	if b == nil {
		return nil, nil
	}
	if hasEventsAttachment(b) {
		return s.readEventsAttachment(b.ID)
	}
	if b.Extra == nil {
		return nil, nil
	}
	if raw, ok := b.Extra["events"]; ok {
		return decodeBeadEvents(raw), nil
	}
	return nil, nil
}

// encodeEventsForExtra mirrors the in-memory shape AppendEvent already uses
// when storing events inline so that round-trips between attachment and inline
// produce identical JSON.
func encodeEventsForExtra(events []BeadEvent) []map[string]any {
	out := make([]map[string]any, 0, len(events))
	for _, e := range events {
		out = append(out, map[string]any{
			"kind":       e.Kind,
			"summary":    e.Summary,
			"body":       e.Body,
			"actor":      e.Actor,
			"created_at": e.CreatedAt,
			"source":     e.Source,
		})
	}
	return out
}

// externalizeEventsInPlace moves a bead's inline events to its sidecar. It
// mutates b: drops Extra["events"] and sets Extra[events_attachment]. The
// sidecar file is written first so a crash leaves the inline copy intact;
// after the row is persisted the inline copy is dropped.
//
// No-op when there are no inline events to move (already externalized, or
// never had any). Removes Extra[events_attachment] when the bead has neither
// inline nor attached events so the row stays clean.
func (s *Store) externalizeEventsInPlace(b *Bead) error {
	if b == nil {
		return nil
	}
	if s.axonGraphQLActive() {
		return nil
	}
	if b.Extra == nil {
		b.Extra = make(map[string]any)
	}
	var inline []BeadEvent
	if raw, ok := b.Extra["events"]; ok {
		inline = decodeBeadEvents(raw)
	}
	if len(inline) == 0 {
		return nil
	}
	if err := s.writeEventsAttachment(b.ID, inline); err != nil {
		return err
	}
	delete(b.Extra, "events")
	b.Extra[EventsAttachmentExtraKey] = eventsAttachmentRelPath(b.ID)
	return nil
}

// LoadEventsInline pulls a bead's externalized events back into Extra["events"]
// for callers that need a single uniform shape (notably JSON output and
// export-for-interchange paths). It does not touch the on-disk row; the bead
// value is mutated in memory only.
func (s *Store) LoadEventsInline(b *Bead) error {
	return s.inlineEventsInPlace(b)
}

// inlineEventsInPlace is the inverse of externalizeEventsInPlace: it loads any
// sidecar events back into Extra["events"] and clears the attachment ref.
// Used by Reopen so an active bead returns to fully-inline storage, and by
// the export path which inlines transiently for marshaling without touching
// the on-disk row (callers that don't want the bead mutated must work on a
// copy — Bead is a value type so the typical usage is to pass a copy).
func (s *Store) inlineEventsInPlace(b *Bead) error {
	if b == nil {
		return nil
	}
	if s.axonGraphQLActive() {
		return nil
	}
	if !hasEventsAttachment(b) {
		return nil
	}
	events, err := s.readEventsAttachment(b.ID)
	if err != nil {
		return err
	}
	if b.Extra == nil {
		b.Extra = make(map[string]any)
	}
	if len(events) > 0 {
		b.Extra["events"] = encodeEventsForExtra(events)
	} else {
		delete(b.Extra, "events")
	}
	delete(b.Extra, EventsAttachmentExtraKey)
	return nil
}

package bead

import (
	"bytes"
	"encoding/json"
	"os"
	"strings"
	"testing"

	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

// TestAttachmentClosingExternalizesEvents asserts that closing a bead moves
// its inline event history into a sidecar attachment under
// .ddx/attachments/<id>/events.jsonl and clears the inline copy from the row.
//
// Acceptance: AC1 (closed beads write events to the attachment store, not
// inline) and AC3 (bead-row size shrinks).
func TestAttachmentClosingExternalizesEvents(t *testing.T) {
	s := newTestStore(t)

	b := &Bead{Title: "to close"}
	require.NoError(t, s.Create(b))
	require.NoError(t, s.AppendEvent(b.ID, BeadEvent{Kind: "review", Summary: "APPROVE", Body: "looks good"}))
	require.NoError(t, s.AppendEvent(b.ID, BeadEvent{Kind: "summary", Summary: "completed"}))

	// Capture the row size before close so we can demonstrate AC3 shrinkage.
	beforeRowBytes := len(beadRowBytes(t, s, b.ID))

	require.NoError(t, s.Close(b.ID))

	// Sidecar exists.
	attPath := s.eventsAttachmentPath(b.ID)
	info, err := os.Stat(attPath)
	require.NoError(t, err, "events.jsonl sidecar should exist after close")
	assert.True(t, info.Size() > 0)

	// The on-disk row no longer carries inline events; it carries an
	// attachment ref instead.
	rowBytes := beadRowBytes(t, s, b.ID)
	assert.NotContains(t, string(rowBytes), `"events":`)
	assert.Contains(t, string(rowBytes), `"`+EventsAttachmentExtraKey+`":`)

	// AC3: the row shrank.
	assert.Less(t, len(rowBytes), beforeRowBytes,
		"closed bead row should be smaller after externalization")

	// Sidecar carries both events with their bodies intact.
	events, err := s.readEventsAttachment(b.ID)
	require.NoError(t, err)
	require.Len(t, events, 2)
	assert.Equal(t, "review", events[0].Kind)
	assert.Equal(t, "APPROVE", events[0].Summary)
	assert.Equal(t, "looks good", events[0].Body)
	assert.Equal(t, "summary", events[1].Kind)
}

// TestAttachmentShowReadsTransparently exercises AC2: callers read events
// through the normal Events() API regardless of where they live, and the
// `--json` show projection inlines events into the marshaled object.
func TestAttachmentShowReadsTransparently(t *testing.T) {
	s := newTestStore(t)

	b := &Bead{Title: "show me"}
	require.NoError(t, s.Create(b))
	require.NoError(t, s.AppendEvent(b.ID, BeadEvent{Kind: "routing", Summary: "model=opus"}))
	require.NoError(t, s.AppendEvent(b.ID, BeadEvent{Kind: "review", Summary: "APPROVE", Body: "rationale"}))
	require.NoError(t, s.Close(b.ID))

	// Events() returns the externalized log transparently.
	events, err := s.Events(b.ID)
	require.NoError(t, err)
	require.Len(t, events, 2)
	assert.Equal(t, "routing", events[0].Kind)
	assert.Equal(t, "review", events[1].Kind)

	// LoadEventsInline replays the events into Extra["events"] so the JSON
	// show path projects a single uniform shape.
	got, err := s.Get(b.ID)
	require.NoError(t, err)
	require.NotNil(t, got)
	require.NoError(t, s.LoadEventsInline(got))
	raw, ok := got.Extra["events"]
	require.True(t, ok, "LoadEventsInline must populate Extra[events]")
	inlined := decodeBeadEvents(raw)
	require.Len(t, inlined, 2)
	_, attachStillSet := got.Extra[EventsAttachmentExtraKey]
	assert.False(t, attachStillSet, "in-memory inlining drops the attachment ref")

	// On-disk row was not modified by the inline operation.
	rowBytes := beadRowBytes(t, s, b.ID)
	assert.NotContains(t, string(rowBytes), `"events":`)
	assert.Contains(t, string(rowBytes), `"`+EventsAttachmentExtraKey+`":`)
}

// TestAttachmentExportInlinesEvents covers AC4: export emits a single inline
// `events` array per row so bd/br interchange survives.
func TestAttachmentExportInlinesEvents(t *testing.T) {
	s := newTestStore(t)

	b := &Bead{Title: "export me"}
	require.NoError(t, s.Create(b))
	require.NoError(t, s.AppendEvent(b.ID, BeadEvent{Kind: "routing", Summary: "model=opus"}))
	require.NoError(t, s.AppendEvent(b.ID, BeadEvent{Kind: "review", Summary: "APPROVE", Body: "ok"}))
	require.NoError(t, s.Close(b.ID))

	var buf bytes.Buffer
	require.NoError(t, s.ExportTo(&buf))

	out := strings.TrimSpace(buf.String())
	require.NotEmpty(t, out)

	var row map[string]any
	require.NoError(t, json.Unmarshal([]byte(out), &row))

	events, ok := row["events"].([]any)
	require.True(t, ok, "export must include inline events array; got %v", row["events"])
